queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTools ?child ; p:hasEditing_Suites ?parent . } GROUP BY ?child }
  ?child p:Type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Editing_Suites } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?type WHERE {
  ?editing_suites_tools a :Editing_Suites_Tools .
  ?tools a :Tools .
  ?editing_suites_tools p:hasTools ?tools .
  ?editing_suites a :Editing_Suites .
  ?editing_suites_tools p:hasEditing_Suites ?editing_suites .
  ?editing_suites p:name ?name .
  ?tools p:Type ?type .
} }
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTools ?child ; p:hasEditing_Suites ?parent . } GROUP BY ?child }
  ?child p:Type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Editing_Suites } }
  FILTER(?nf = ?total)
} }
}
